package com.hospital.management.dao.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.time.*;import java.util.*;
/** Oracle prescription header persistence; detail rows are loaded only for single-record views. */public class PrescriptionDaoImpl implements PrescriptionDao {private final PrescriptionItemDao items;private static final String S="SELECT rx.*,p.PATIENT_NUMBER,p.FIRST_NAME||' '||p.LAST_NAME PATIENT_NAME,d.FIRST_NAME||' '||d.LAST_NAME DOCTOR_NAME,d.DEPARTMENT_ID,dep.DEPARTMENT_NAME,a.APPOINTMENT_DATE FROM PRESCRIPTIONS rx JOIN MEDICAL_RECORDS m ON m.MEDICAL_RECORD_ID=rx.MEDICAL_RECORD_ID JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=rx.APPOINTMENT_ID JOIN PATIENTS p ON p.PATIENT_ID=rx.PATIENT_ID JOIN DOCTORS d ON d.DOCTOR_ID=rx.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ";public PrescriptionDaoImpl(){this(new PrescriptionItemDaoImpl());}public PrescriptionDaoImpl(PrescriptionItemDao i){items=i;}public Optional<Prescription>findById(Long id)throws SQLException{return one("rx.PRESCRIPTION_ID",id);}public Optional<Prescription>findByMedicalRecordId(Long id)throws SQLException{return one("rx.MEDICAL_RECORD_ID",id);}private Optional<Prescription>one(String f,Long id)throws SQLException{if(id==null)return Optional.empty();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+"WHERE "+f+"=?")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){if(!r.next())return Optional.empty();Prescription p=map(r);p.setItems(items.findByPrescriptionId(p.getPrescriptionId()));return Optional.of(p);}}}
public Page<Prescription>findAll(PageRequest p,Long pi,Long di,Long dep,LocalDate from,LocalDate to,String st)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+where()+" ORDER BY rx.PRESCRIPTION_DATE DESC,rx.PRESCRIPTION_ID DESC OFFSET ? ROWS FETCH NEXT ? ROWS ONLY")){int n=bind(s,p.getSearchTerm(),pi,di,dep,from,to,st);s.setInt(n++,p.getOffset());s.setInt(n,p.getPageSize());List<Prescription>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return new Page<>(x,p.getPageNumber(),p.getPageSize(),count(p.getSearchTerm(),pi,di,dep,from,to,st));}}public long count(String q,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st)throws SQLException{String from="FROM PRESCRIPTIONS rx JOIN MEDICAL_RECORDS m ON m.MEDICAL_RECORD_ID=rx.MEDICAL_RECORD_ID JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=rx.APPOINTMENT_ID JOIN PATIENTS p ON p.PATIENT_ID=rx.PATIENT_ID JOIN DOCTORS d ON d.DOCTOR_ID=rx.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT COUNT(1) "+from+where())){bind(s,q,pi,di,dep,f,t,st);try(ResultSet r=s.executeQuery()){r.next();return r.getLong(1);}}}
private String where(){return"WHERE (? IS NULL OR UPPER(p.PATIENT_NUMBER||' '||p.FIRST_NAME||' '||p.LAST_NAME||' '||d.FIRST_NAME||' '||d.LAST_NAME||' '||dep.DEPARTMENT_NAME||' '||rx.NOTES||' '||rx.STATUS) LIKE ? ESCAPE '\\' OR EXISTS(SELECT 1 FROM PRESCRIPTION_ITEMS ix WHERE ix.PRESCRIPTION_ID=rx.PRESCRIPTION_ID AND UPPER(ix.MEDICINE_NAME) LIKE ? ESCAPE '\\')) AND (? IS NULL OR rx.PATIENT_ID=?) AND (? IS NULL OR rx.DOCTOR_ID=?) AND (? IS NULL OR d.DEPARTMENT_ID=?) AND (? IS NULL OR rx.PRESCRIPTION_DATE>=?) AND (? IS NULL OR rx.PRESCRIPTION_DATE<?) AND (? IS NULL OR rx.STATUS=?) ";}private int bind(PreparedStatement s,String q,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st)throws SQLException{String x=q==null||q.isBlank()?null:"%"+q.trim().toUpperCase().replace("\\","\\\\").replace("%","\\%").replace("_","\\_")+"%";int i=1;s.setString(i++,x);s.setString(i++,x);s.setString(i++,x);i=pair(s,i,pi);i=pair(s,i,di);i=pair(s,i,dep);i=date(s,i,f);i=date(s,i,t==null?null:t.plusDays(1));String z=st==null||st.isBlank()?null:st.toUpperCase();s.setString(i++,z);s.setString(i++,z);return i;}private int pair(PreparedStatement s,int i,Long v)throws SQLException{if(v==null){s.setNull(i++,Types.NUMERIC);s.setNull(i++,Types.NUMERIC);}else{s.setLong(i++,v);s.setLong(i++,v);}return i;}private int date(PreparedStatement s,int i,LocalDate v)throws SQLException{if(v==null){s.setNull(i++,Types.DATE);s.setNull(i++,Types.DATE);}else{s.setDate(i++,java.sql.Date.valueOf(v));s.setDate(i++,java.sql.Date.valueOf(v));}return i;}
public long createPrescription(Connection c,Prescription p)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO PRESCRIPTIONS(PATIENT_ID,DOCTOR_ID,APPOINTMENT_ID,MEDICAL_RECORD_ID,PRESCRIPTION_DATE,VALID_UNTIL,NOTES,STATUS)VALUES(?,?,?,?,?,?,?,?)",new String[]{"PRESCRIPTION_ID"})){s.setLong(1,p.getPatientId());s.setLong(2,p.getDoctorId());s.setLong(3,p.getAppointmentId());s.setLong(4,p.getMedicalRecordId());s.setDate(5,java.sql.Date.valueOf(p.getPrescriptionDate()));if(p.getValidUntil()==null)s.setNull(6,Types.DATE);else s.setDate(6,java.sql.Date.valueOf(p.getValidUntil()));s.setString(7,p.getNotes());s.setString(8,p.getStatus());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){if(r.next())return r.getLong(1);}throw new SQLException("No prescription identifier returned");}}public boolean updatePrescription(Connection c,Prescription p)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE PRESCRIPTIONS SET VALID_UNTIL=?,NOTES=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE PRESCRIPTION_ID=?")){if(p.getValidUntil()==null)s.setNull(1,Types.DATE);else s.setDate(1,java.sql.Date.valueOf(p.getValidUntil()));s.setString(2,p.getNotes());s.setLong(3,p.getPrescriptionId());return s.executeUpdate()==1;}}public boolean updateStatus(Connection c,Long id,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE PRESCRIPTIONS SET STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE PRESCRIPTION_ID=?")){s.setString(1,st);s.setLong(2,id);return s.executeUpdate()==1;}}public boolean existsByMedicalRecordId(Long id)throws SQLException{return exists(id,null);}public boolean existsByMedicalRecordIdExcludingPrescription(Long m,Long p)throws SQLException{return exists(m,p);}private boolean exists(Long m,Long p)throws SQLException{String q="SELECT 1 FROM PRESCRIPTIONS WHERE MEDICAL_RECORD_ID=?"+(p==null?"":" AND PRESCRIPTION_ID<>?")+" FETCH FIRST 1 ROW ONLY";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(q)){s.setLong(1,m);if(p!=null)s.setLong(2,p);try(ResultSet r=s.executeQuery()){return r.next();}}}
private Prescription map(ResultSet r)throws SQLException{Prescription p=new Prescription();p.setPrescriptionId(r.getLong("PRESCRIPTION_ID"));p.setPatientId(r.getLong("PATIENT_ID"));p.setPatientNumber(r.getString("PATIENT_NUMBER"));p.setPatientName(r.getString("PATIENT_NAME"));p.setDoctorId(r.getLong("DOCTOR_ID"));p.setDoctorName(r.getString("DOCTOR_NAME"));p.setDepartmentId(r.getLong("DEPARTMENT_ID"));p.setDepartmentName(r.getString("DEPARTMENT_NAME"));p.setAppointmentId(r.getLong("APPOINTMENT_ID"));p.setMedicalRecordId(r.getLong("MEDICAL_RECORD_ID"));p.setPrescriptionDate(r.getDate("PRESCRIPTION_DATE").toLocalDate());java.sql.Date v=r.getDate("VALID_UNTIL"),a=r.getDate("APPOINTMENT_DATE");p.setValidUntil(v==null?null:v.toLocalDate());p.setAppointmentDate(a==null?null:a.toLocalDate());p.setNotes(r.getString("NOTES"));p.setStatus(r.getString("STATUS"));Timestamp c=r.getTimestamp("CREATED_AT"),u=r.getTimestamp("UPDATED_AT");p.setCreatedAt(c==null?null:c.toLocalDateTime());p.setUpdatedAt(u==null?null:u.toLocalDateTime());return p;}}
